dec_med = pow (0.6, 30/fps);;
dec_slow = pow (0.9, 30/fps);;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (.2+avg+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %8;;
index2 = (index2 + is_beat*bnot(index))%4;;
index3 = (index3 + is_beat*bnot(index)*bnot(index2))%3;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q23 = index;;
q24 = is_beat;;
q26 = bass + mid + treb;;
ava = ava*dec_slow + q26*(1-dec_slow);;
//k1 =  is_beat*bnot(index)*bnot(index2);;
k1 =  is_beat*((index%2) == (0));;
p1 =  k1*(p1+1) + (1-k1)*p1;;
p2 = dec_med * p2+ (1-dec_med)*p1;;
rott = p2 * 3.1416/2;;
q1 = cos(rott);;
q2 = sin(rott);;
q3 = -q2;;
q4 = q1;;
q27 = 8-index;;
q28 = .5 + sin(time/7)/10;;
rm = min(q26-1.5*ava,2);;
mov = is_beat*rm + (1-is_beat)*mov;;
movez = movez + .4/fps*mov;;
q30 = movez;;
//**************************;
ampl = q26/8;;
movex = movex + .2/fps*sin(rott);;
movey = movey + .2/fps*cos(rott);;
q18 = movex; q19 = movey;;
